    fun createUserCustomerLinksWithHttpInfo(bankid: kotlin.String, createUserCustomerLinksRequest: CreateUserCustomerLinksRequest) : ApiResponse<GetUserCustomerLinksByCustomerId200ResponseUserCustomerLinksInner?> {
